import { useEffect, useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Users,
  UsersRound,
  CalendarCheck,
  ClipboardCheck,
  CheckCircle,
  XCircle,
  AlertTriangle,
} from "lucide-react";

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  const [pending, setPending] = useState({
    students: [],
    results: [],
    attendance: [],
    payments: [],
    announcements: [],
    total: 0,
  });

  const [loading, setLoading] = useState(true);

  const user = authService.getUser();

  // ✅ FIX: normalize role safely
  const role = (user?.role || "").toLowerCase();

  const isAdmin =
    role === "school_admin" || role === "admin";

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      // =========================
      // STATS (SAFE)
      // =========================
      try {
        const statsRes = await apiClient.get("/dashboard/stats");
        setStats(statsRes?.data || {});
      } catch (err) {
        console.log("Stats endpoint missing or broken");
        setStats({});
      }

      // =========================
      // ADMIN PENDING
      // =========================
      if (isAdmin) {
        try {
          const pendingRes = await apiClient.get("/admin/pending");

          setPending({
            students: pendingRes?.data?.students || [],
            results: pendingRes?.data?.results || [],
            attendance: pendingRes?.data?.attendance || [],
            payments: pendingRes?.data?.payments || [],
            announcements: pendingRes?.data?.announcements || [],
            total: pendingRes?.data?.total || 0,
          });
        } catch (err) {
          console.log("Pending endpoint not ready yet");
          setPending({
            students: [],
            results: [],
            attendance: [],
            payments: [],
            announcements: [],
            total: 0,
          });
        }
      }
    } catch (error) {
      console.error("Dashboard error:", error);
      toast.error("Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  };

  const handleApproval = async (itemType, itemId, action) => {
    try {
      await apiClient.patch(
        `/admin/approve/${itemType}/${itemId}`,
        { action }
      );

      toast.success(`${itemType} ${action} successfully`);
      fetchData();
    } catch (error) {
      console.error(error);
      toast.error(`Failed to ${action} ${itemType}`);
    }
  };

  const statCards = [
    {
      title: "Total Students",
      value: stats?.total_students || 0,
      icon: Users,
      accent: "emerald",
    },
    {
      title: "Total Staff",
      value: stats?.total_staff || 0,
      icon: UsersRound,
      accent: "cyan",
    },
    {
      title: "Present Today",
      value: stats?.present_today || 0,
      icon: CalendarCheck,
      accent: "violet",
    },
    {
      title: "Pending Approvals",
      value: pending?.total || 0,
      icon: ClipboardCheck,
      accent: "amber",
    },
  ];

  const accentMap = {
    emerald: { bg: "bg-emerald-500/15", text: "text-emerald-400", border: "border-emerald-500/20" },
    cyan: { bg: "bg-cyan-500/15", text: "text-cyan-400", border: "border-cyan-500/20" },
    violet: { bg: "bg-violet-500/15", text: "text-violet-400", border: "border-violet-500/20" },
    amber: { bg: "bg-amber-500/15", text: "text-amber-400", border: "border-amber-500/20" },
  };

  if (loading) {
    return (
      <div className="text-center py-12 text-slate-400">
        Loading dashboard...
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* HEADER */}
      <div>
        <h2 className="text-2xl font-bold text-white">
          Dashboard Overview
        </h2>
        <p className="text-slate-400 mt-1 text-sm">
          Welcome to Smart-M Hub
        </p>
      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
        {statCards.map((stat, i) => {
          const Icon = stat.icon;
          const a = accentMap[stat.accent];

          return (
            <div
              key={i}
              className={`bg-[#1A2332] border ${a.border} rounded-xl p-5`}
            >
              <div className="flex justify-between mb-3">
                <p className="text-sm text-slate-400">
                  {stat.title}
                </p>
                <div className={`${a.bg} p-2 rounded-lg`}>
                  <Icon className={`w-4 h-4 ${a.text}`} />
                </div>
              </div>

              <p className="text-3xl font-bold text-white">
                {stat.value}
              </p>
            </div>
          );
        })}
      </div>

      {/* ADMIN SECTION */}
      {isAdmin && pending?.total > 0 && (
        <div className="bg-[#1A2332] border border-amber-500/20 rounded-xl p-6">
          <div className="flex items-center gap-2 mb-5">
            <AlertTriangle className="w-5 h-5 text-amber-400" />
            <h3 className="text-white font-semibold">
              Pending Approvals ({pending.total})
            </h3>
          </div>

          <p className="text-slate-400 text-sm">
            Admin approval system loaded.
          </p>
        </div>
      )}

      {isAdmin && pending?.total === 0 && (
        <div className="bg-[#1A2332] border border-emerald-500/20 p-6 rounded-xl text-center">
          <CheckCircle className="w-8 h-8 text-emerald-400 mx-auto mb-2" />
          <p className="text-emerald-400">
            No pending approvals
          </p>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
